VALUES
  ('optician-moex-01399', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡引起的阿米巴角膜潰瘍，下列敘述何者錯誤？', '["避免以自來水沖洗隱形眼鏡後就戴上，可減少發生機會", "避免戴隱形眼鏡游泳，可減少發生機會", "比一般感染，疼痛感較少，易被忽略", "初期常被誤診為皰疹性角膜炎"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01400', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關戴隱形眼鏡者，若有過敏性結膜炎，下列敘述何者錯誤？', '["眼睛癢可以是過敏性結膜炎的症狀，但乾眼症也會造成眼睛癢，因此需小心辨別，才可以對症下藥", "戴隱形眼鏡者，需使用抗組織胺或是類固醇治療過敏者，最好在戴上隱形眼鏡後點藥，會是比較好的時機", "有過敏性結膜炎者，睡覺前洗頭可有效幫助避免過敏原", "有過敏性結膜炎者，冰敷可以幫助緩解症狀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01401', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種眼睛疾患與隱形眼鏡配戴較無關？', '["角膜失養症", "角膜潰瘍", "角膜水腫", "角膜新生血管"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01402', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一位剛滿九歲的小朋友因為配戴角膜塑型鏡片（orthokeratologylens）產生紅眼症狀，他的角膜中央出現點 狀角膜上皮缺損及輕微角膜基質層浸潤，併發過敏性巨大乳突結膜炎（giant papillaryconjunctivitis）及黃 白色分泌物。最適當的處置為何？', '["暫時停止配戴，先用類固醇藥水治療", "給予抗生素藥水治療，並且用紗布覆蓋眼睛", "終止配戴，最好能夠進行細菌培養取得檢體", "生理食鹽水沖洗眼睛，三天後繼續配戴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01403', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡引起的角膜水腫，下列敘述何者錯誤？', '["因為角膜缺氧而產生，使用含水量較低的水膠鏡片可改善", "是因為乳酸堆積在角膜內而產生", "可由長戴型（EW）改為日戴型（DW）以緩解症狀", "隱形眼鏡造成角膜水腫可能會合併角膜內皮細胞多型性（polymegethism）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01404', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關微生物性角膜炎（microbialkeratitis）的敘述，下列何者錯誤？', '["通常病人移除隱形眼鏡時疼痛感減緩", "初期的症狀大多以異物感（foreignbodysensation）為主", "病情嚴重時甚至會眼皮腫（lidswelling）", "患者的眼睛會發紅、充血"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01405', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列敘述何者錯誤？', '["角膜內皮層因為細胞流失（例如衰老）或長期缺氧導致細胞增大或大小不一的情況，稱為角膜內皮細胞 多型性", "當角膜水腫大於8%時會出現角膜皺褶（folds）", "檢驗角膜和結膜完整性及驗配硬性鏡片時不可缺少的染劑為循血綠（indocyaninegreen,ICG）", "矽（silicone）為一種化學元素，可以增加隱形眼鏡透氧度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01406', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '使用水膠（hydrogel）材質的軟式隱形眼鏡時，配戴過夜較容易造成角膜缺氧而使得角膜水腫皺摺（striae andfolds），這類型角膜水腫較少產生下列那一症狀？', '["視力模糊", "畏光", "看到光暈", "眼壓過高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01407', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '長期使用單眼視覺法（monovision）隱形眼鏡的患者，但最近覺得幾年前驗配的 +1.50D近用度數在閱讀 上已經不太清楚，但他又不能適應您三週前為他驗配的 +2.50D近用度數。和他討論後，決定將他的近用 度數降回 +1.50D並加配一副老花眼鏡來搭配使用，此種驗配法稱為？', '["部分單眼視覺（partialmonovision）", "增強單眼視覺（enhancedmonovision）", "完整單眼視覺（completedmonovision）", "戴鏡單眼視覺（spectaclemonovision）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01408', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於轉換（translating）設計的雙焦點隱形眼鏡，何者錯誤？', '["是同步視覺設計（simultaneousvisiondesign）隱形眼鏡的一種", "鏡片設計為上面看遠，下面看近", "鏡片的設計會利用下眼瞼作為止動間隙（stopgap），因此眼皮不能太鬆", "鏡片一般會有稜鏡垂重（prism-ballasted）或截邊（truncated）設計"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
